class MinHeap {
  constructor() { this.heap = []; }
  size() { return this.heap.length; }
  peek() { return this.heap[0]; }
  push(val) {
    this.heap.push(val);
    let i = this.heap.length - 1;
    while (i > 0) {
      const parent = (i - 1) >> 1;
      if (this._key(this.heap[parent]) <= this._key(this.heap[i])) {
        break;
      }
      [this.heap[parent], this.heap[i]] = [this.heap[i], this.heap[parent]];
      i = parent;
    }
  } 
  pop() {
    const top = this.heap[0];
    const last = this.heap.pop();
    if (this.heap.length > 0) {
      this.heap[0] = last;
      const n = this.heap.length;
      let i = 0;
      while (true) {
        let smallest = i;
        const left = 2 * i + 1;
        const right = 2 * i + 2;
        if (left < n && this._key(this.heap[left]) < this._key(this.heap[smallest])) { smallest = left; }
        if (right < n && this._key(this.heap[right]) < this._key(this.heap[smallest])) { smallest = right; }
        if (smallest === i) { break; }
        [this.heap[smallest], this.heap[i]] = [this.heap[i], this.heap[smallest]];
        i = smallest;
      }
    }
    return top;
  }
  _key(item) {
    return item.endTime !== undefined ? item.endTime : item.roomId;
  }
}

